// Copyright (c) HashiCorp, Inc.// SPDX-License-Identifier: MITpackage hclogimport (	"io"	"io/ioutil"	"log")// NewNullLogger instantiates a Logger for which all calls// will succeed without doing anything.// Useful for testing purposes.NullLogger() Logger {	return &nullLogger{}}type nullLogger struct{}*nullLogger) Log(level Level, msg string, args ...interface{}) {}*nullLogger) Trace(msg string, args ...interface{}) {}*nullLogger) Debug(msg string, args ...interface{}) {}*nullLogger) Info(msg string, args ...interface{}) {}*nullLogger) Warn(msg string, args ...interface{}) {}*nullLogger) Error(msg string, args ...interface{}) {}*nullLogger) IsTrace() bool { return false }*nullLogger) IsDebug() bool { return false }*nullLogger) IsInfo() bool { return false }*nullLogger) IsWarn() bool { return false }*nullLogger) IsError() bool { return false }*nullLogger) ImpliedArgs() []interface{} { return []interface{}{} }*nullLogger) With(args ...interface{}) Logger { return l }*nullLogger) Name() string { return "" }*nullLogger) Named(name string) Logger { return l }*nullLogger) ResetNamed(name string) Logger { return l }*nullLogger) SetLevel(level Level) {}*nullLogger) GetLevel() Level { return NoLevel }*nullLogger) StandardLogger(opts *StandardLoggerOptions) *log.Logger {	return log.New(l.StandardWriter(opts), "", log.LstdFlags)}*nullLogger) StandardWriter(opts *StandardLoggerOptions) io.Writer {	return ioutil.Discard}